// ── Synchronisation Google Contacts → Baserow ────────────────────
// Ce nœud lit tous les contacts Google reçus et les upserte dans
// la table contacts_admin (ID 544) de Baserow.
// Logique :
//   - Si l'email existe déjà → PATCH (mise à jour Prénom, Nom, Tél, Entreprise)
//   - Sinon → POST (création avec Catégorie=Admin)

const data = $input.first().json;
const connections = data.connections || [];

const BASE  = 'https://baserow.ananda-communaute.cloud/api';
const TOKEN = 'GBLdzaCZvQUVXkCqSls3WX3dT3uVg0H8';
const TABLE = 544;
const h     = {
  'Authorization': `Token ${TOKEN}`,
  'Content-Type': 'application/json'
};

let created = 0;
let updated = 0;
let skipped = 0;

for (const person of connections) {
  // ── Extraire les champs ──
  const email     = (person.emailAddresses?.[0]?.value || '').trim();
  if (!email) { skipped++; continue; }

  const prénom    = person.names?.[0]?.givenName  || '';
  const nom       = person.names?.[0]?.familyName || '';
  const téléphone = person.phoneNumbers?.[0]?.value || '';
  const entreprise= person.organizations?.[0]?.name || '';

  // ── Vérifier si le contact existe déjà dans Baserow ──
  const searchUrl = `${BASE}/database/rows/table/${TABLE}/?user_field_names=true&filter__Email__equal=${encodeURIComponent(email)}`;
  const searchRes  = await fetch(searchUrl, { headers: h });
  const searchData = await searchRes.json();

  if (searchData.count > 0) {
    // ── Mise à jour (ne pas écraser l'email ni les Notes) ──
    const rowId = searchData.results[0].id;
    await fetch(
      `${BASE}/database/rows/table/${TABLE}/${rowId}/?user_field_names=true`,
      {
        method: 'PATCH',
        headers: h,
        body: JSON.stringify({ Prénom: prénom, Nom: nom, Téléphone: téléphone, Entreprise: entreprise })
      }
    );
    updated++;
  } else {
    // ── Création ──
    await fetch(
      `${BASE}/database/rows/table/${TABLE}/?user_field_names=true`,
      {
        method: 'POST',
        headers: h,
        body: JSON.stringify({
          Prénom:     prénom,
          Nom:        nom,
          Email:      email,
          Téléphone:  téléphone,
          Entreprise: entreprise,
          Catégorie:  'Admin'
        })
      }
    );
    created++;
  }
}

return [{
  json: {
    ok:        true,
    total:     connections.length,
    created,
    updated,
    skipped,
    timestamp: new Date().toISOString()
  }
}];
